 * mmap fichier pour persister un entier
 * ================================================= */
void example_mmap_file(void) {
    char tmp[] = "/tmp/kf_ex_mmap_XXXXXX";
    int fd = mkstemp(tmp);
    ftruncate(fd, sizeof(int));
    int *p = (int *)mmap(NULL, sizeof(int), PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0);
    *p = 123;
    msync(p, sizeof(int), MS_SYNC);
    munmap(p, sizeof(int));
    p = (int *)mmap(NULL, sizeof(int), PROT_READ, MAP_SHARED, fd, 0);
    printf("Persisted: %d\n", *p);
    munmap(p, sizeof(int));
    close(fd); unlink(tmp);
}
